example.code:
containers:
- name: web
  image: nginx:1.25
  resources:
    requests: {cpu: 200m, memory: 256Mi}
    limits: {cpu: 500m, memory: 512Mi}
- name: fluentbit
  image: fluent/fluent-bit:2.2
  resources:
    requests: {cpu: 50m, memory: 64Mi}
    limits: {cpu: 100m, memory: 128Mi}
initContainers:
- name: init-db
  image: busybox:1.36
  resources:
    requests: {cpu: 10m, memory: 16Mi}
    limits: {cpu: 50m, memory: 32Mi}
